pub unsafe fn unlock(&self) {
    let prev = self.locked.fetch_sub(1, Release);

    // If the previous value was 1, then this was a "fast path" unlock, so no
    // need to involve the Ticktimer server
    if prev == 1 {
        return;
    }

    // If it was 0, then something has gone seriously wrong and the counter
    // has just wrapped around.
    if prev == 0 {
        panic!("mutex lock count underflowed");
    }

    // Unblock one thread that is waiting on this message.
    blocking_scalar(ticktimer_server(), TicktimerScalar::UnlockMutex(self.index()).into())
        .expect("failure to send UnlockMutex command");
}

fn pare_down(candidates: &mut Vec<usize>, closure: &BitMatrix<usize, usize>) {
    let mut i = 0;
    while let Some(&candidate_i) = candidates.get(i) {
        i += 1;

        let mut j = i;
        let mut dead = 0;
        while let Some(&candidate_j) = candidates.get(j) {
            if closure.contains(candidate_i, candidate_j) {
                // If `i` can reach `j`, then we can remove `j`. So just
                // mark it as dead and move on; subsequent indices will be
                // shifted into its place.
                dead += 1;
            } else {
                candidates[j - dead] = candidate_j;
            }
            j += 1;
        }
        candidates.truncate(j - dead);
    }
}

fn fold_until(&mut self, level: u32) {
    let mut this = None;
    loop {
        match self.chain.pop() {
            Some(mut next) => {
                next.children.entries.extend(this);
                if next.level < level {
                    // this is the parent we want, so return it to
                    // its rightful place.
                    self.chain.push(next);
                    return;
                } else {
                    this = Some(next);
                }
            }
            None => {
                self.top_level.entries.extend(this);
                return;
            }
        }
    }
}

pub(crate) unsafe fn write(&self, slot_index: usize, value: T) {
    // Get the offset into the block
    let slot_offset = offset(slot_index);

    self.values[slot_offset].with_mut(|ptr| {
        // Safety: the caller guarantees that there is no concurrent access to the slot
        unsafe {
            ptr::write(ptr, MaybeUninit::new(value));
        }
    });

    // Release the value. After this point, the slot ref may no longer
    // be used. It is possible for the receiver to free the memory at
    // any point.
    self.set_ready(slot_offset);
}

fn next_expiration(&self) -> Option<Expiration> {
    if !self.pending.is_empty() {
        // Expire immediately as we have things pending firing
        return Some(Expiration {
            level: 0,
            slot: 0,
            deadline: self.elapsed,
        });
    }

    // Check all levels
    for (level_num, level) in self.levels.iter().enumerate() {
        if let Some(expiration) = level.next_expiration(self.elapsed) {
            // There cannot be any expirations at a higher level that happen
            // before this one.
            debug_assert!(self.no_expirations_before(level_num + 1, expiration.deadline));

            return Some(expiration);
        }
    }

    None
}

fn to_symboltrace(backtrace: Backtrace) -> SymbolTrace {
    // Resolve the backtrace frames to symbols.
    let backtrace: Backtrace = {
        let mut backtrace = backtrace::Backtrace::from(backtrace);
        backtrace.resolve();
        backtrace.into()
    };

    // Accumulate the symbols in descending order into `symboltrace`.
    let mut symboltrace: SymbolTrace = vec![];
    let mut state = DefaultHasher::new();
    for frame in backtrace.into_iter().rev() {
        for symbol in frame.symbols().iter().rev() {
            let symbol = Symbol {
                symbol: symbol.clone(),
                parent_hash: state.finish(),
            };
            symbol.hash(&mut state);
            symboltrace.push(symbol);
        }
    }

    symboltrace
}

pub fn requote(&self, val: &[u8]) -> Option<Vec<u8>> {
    let mut remaining = val;

    // early return indicates that no percent-encoded sequences exist and we can skip allocation
    let (pre, decoded_char) = self.decode_next(&mut remaining)?;

    // decoded output will always be shorter than the input
    let mut decoded = Vec::<u8>::with_capacity(val.len());

    // push first segment and decoded char
    decoded.extend_from_slice(pre);
    decoded.push(decoded_char);

    // decode and push rest of segments and decoded chars
    while let Some((prev, ch)) = self.decode_next(&mut remaining) {
        // this ugly conditional achieves +50% perf in cases where this is a tight loop.
        if !prev.is_empty() {
            decoded.extend_from_slice(prev);
        }
        decoded.push(ch);
    }

    decoded.extend_from_slice(remaining);

    Some(decoded)
}

fn multiple(args: Vec<Args>, ast: syn::ItemFn) -> syn::Result<Self> {
    let name = ast.sig.ident.clone();

    // Try and pull out the doc comments so that we can reapply them to the generated struct.
    // Note that multi line doc comments are converted to multiple doc attributes.
    let doc_attributes = ast
        .attrs
        .iter()
        .filter(|attr| attr.path().is_ident("doc"))
        .cloned()
        .collect();

    if matches!(ast.sig.output, syn::ReturnType::Default) {
        return Err(syn::Error::new_spanned(
            ast,
            "Function has no return type. Cannot be used as handler",
        ));
    }

    Ok(Self {
        name,
        args,
        ast,
        doc_attributes,
    })
}

fn test_invalid_defs() {
    let mut btypes = TypesBuilder::new();
    for tydef in types() {
        btypes.add_def(tydef).unwrap();
    }
    // Preserve the original definitions for later comparison.
    let original_defs = btypes.definitions();
    let bad_defs = vec![
        // Reference to type that does not exist
        "combo:include:html,qwerty",
        // Bad format
        "combo:foobar:html,rust",
        "",
    ];
    for def in bad_defs {
        assert!(btypes.add_def(def).is_err());
        // Ensure that nothing changed, even if some of the includes were valid.
        assert_eq!(btypes.definitions(), original_defs);
    }
}

pub(crate) fn build<W: WriteColor>(
    &self,
    matcher: PatternMatcher,
    searcher: grep::searcher::Searcher,
    printer: Printer<W>,
) -> SearchWorker<W> {
    let config = self.config.clone();
    let command_builder = self.command_builder.clone();
    let decomp_builder = config.search_zip.then(|| {
        let mut decomp_builder =
            grep::cli::DecompressionReaderBuilder::new();
        decomp_builder.async_stderr(true);
        decomp_builder
    });
    SearchWorker {
        config,
        command_builder,
        decomp_builder,
        matcher,
        searcher,
        printer,
    }
}

pub(crate) fn len(&self) -> usize {
    loop {
        // Load the tail, then load the head.
        let tail = self.tail.load(Ordering::SeqCst);
        let head = self.head.load(Ordering::SeqCst);

        // If the tail didn't change, we've got consistent values to work with.
        if self.tail.load(Ordering::SeqCst) == tail {
            let hix = head & (self.mark_bit - 1);
            let tix = tail & (self.mark_bit - 1);

            return if hix < tix {
                tix - hix
            } else if hix > tix {
                self.cap() - hix + tix
            } else if (tail & !self.mark_bit) == head {
                0
            } else {
                self.cap()
            };
        }
    }
}

pub(crate) fn try_recv(&self) -> Result<Instant, TryRecvError> {
    // We use relaxed ordering because this is just an optional optimistic check.
    if self.received.load(Ordering::Relaxed) {
        // The message has already been received.
        return Err(TryRecvError::Empty);
    }

    if Instant::now() < self.delivery_time {
        // The message was not delivered yet.
        return Err(TryRecvError::Empty);
    }

    // Try receiving the message if it is still available.
    if !self.received.swap(true, Ordering::SeqCst) {
        // Success! Return delivery time as the message.
        Ok(self.delivery_time)
    } else {
        // The message was already received.
        Err(TryRecvError::Empty)
    }
}

unsafe fn destroy(this: *mut Self, start: usize) {
    // It is not necessary to set the `DESTROY` bit in the last slot because that slot has
    // begun destruction of the block.
    for i in start..BLOCK_CAP - 1 {
        let slot = unsafe { (*this).slots.get_unchecked(i) };

        // Mark the `DESTROY` bit if a thread is still using the slot.
        if slot.state.load(Ordering::Acquire) & READ == 0
            && slot.state.fetch_or(DESTROY, Ordering::AcqRel) & READ == 0
        {
            // If a thread is still using the slot, it will continue destruction of the block.
            return;
        }
    }

    // No thread is using the block, now it is safe to destroy it.
    drop(unsafe { Box::from_raw(this) });
}

pub fn len(&self) -> usize {
    loop {
        // Load the tail, then load the head.
        let tail = self.tail.load(Ordering::SeqCst);
        let head = self.head.load(Ordering::SeqCst);

        // If the tail didn't change, we've got consistent values to work with.
        if self.tail.load(Ordering::SeqCst) == tail {
            let hix = head & (self.one_lap - 1);
            let tix = tail & (self.one_lap - 1);

            return if hix < tix {
                tix - hix
            } else if hix > tix {
                self.capacity() - hix + tix
            } else if tail == head {
                0
            } else {
                self.capacity()
            };
        }
    }
}

pub(crate) fn optimistic_read(&self) -> Option<(usize, usize)> {
    // The acquire loads from `state_hi` and `state_lo` synchronize with the release stores in
    // `SeqLockWriteGuard::drop`.
    //
    // As a consequence, we can make sure that (1) all writes within the era of `state_hi - 1`
    // happens before now; and therefore, (2) if `state_lo` is even, all writes within the
    // critical section of (`state_hi`, `state_lo`) happens before now.
    let state_hi = self.state_hi.load(Ordering::Acquire);
    let state_lo = self.state_lo.load(Ordering::Acquire);
    if state_lo == 1 {
        None
    } else {
        Some((state_hi, state_lo))
    }
}

fn drop(&mut self) {
    let state_lo = self.state_lo.wrapping_add(2);

    // Increase the high bits if the low bits wrap around.
    //
    // Release ordering for synchronizing with `optimistic_read`.
    if state_lo == 0 {
        let state_hi = self.lock.state_hi.load(Ordering::Relaxed);
        self.lock
            .state_hi
            .store(state_hi.wrapping_add(1), Ordering::Release);
    }

    // Release the lock and increment the stamp.
    //
    // Release ordering for synchronizing with `optimistic_read`.
    self.lock.state_lo.store(state_lo, Ordering::Release);
}

pub fn wait(self) {
    // SAFETY: this is equivalent to let Self { inner } = self, without calling our Drop.
    let inner = unsafe {
        let slf = ManuallyDrop::new(self);
        core::ptr::read(&slf.inner)
    };

    if inner.count.fetch_sub(1, Ordering::AcqRel) == 1 {
        // Acquire lock after updating count, see below.
        drop(inner.lock.lock().unwrap());
        inner.cvar.notify_all();
        return;
    }

    // We check the counter while holding the lock, and notifiers acquire
    // the lock between updating the counter and notifying, ensuring we
    // can not miss the notification.
    let mut guard = inner.lock.lock().unwrap();
    while inner.count.load(Ordering::Acquire) != 0 {
        guard = inner.cvar.wait(guard).unwrap();
    }
}

pub fn analyze_sync(
  &self,
  specifier: &ModuleSpecifier,
  media_type: MediaType,
  source: &Arc<str>,
) -> Result<ModuleInfo, deno_ast::ParseDiagnostic> {
  // attempt to load from the cache
  let source_hash = CacheDBHash::from_hashable(source);
  if let Some(info) =
    self.load_cached_module_info(specifier, media_type, source_hash)
  {
    return Ok(info);
  }

  // otherwise, get the module info from the parsed source cache
  let parser = self.parsed_source_cache.as_capturing_parser();
  let analyzer = ParserModuleAnalyzer::new(&parser);
  let module_info =
    analyzer.analyze_sync(specifier, source.clone(), media_type)?;

  // then attempt to cache it
  self.save_module_info_to_cache(
    specifier,
    media_type,
    source_hash,
    &module_info,
  );

  Ok(module_info)
}

pub fn set_is_known_script(&self, specifier: &Url, is_script: bool) {
  let new_value = if is_script {
    ResolutionMode::Require
  } else {
    ResolutionMode::Import
  };
  // block to really ensure dashmap is not borrowed while trying to insert
  {
    if let Some(value) = self.known.get(specifier) {
      // you shouldn't be insert a value in here that's
      // already known and is a different value than what
      // was previously determined
      debug_assert_eq!(*value, new_value);
      return;
    }
  }
  self.known.insert(specifier.clone(), new_value);
}

fn test_droppable() {
  // Make sure we correctly drop all the items in this arena if they are droppable
  let arena = RawArena::<_>::with_capacity(16);
  unsafe {
    let mut nodes = vec![];
    // This will spill over into memory allocations
    for i in 0..20 {
      let node = arena.allocate();
      std::ptr::write(
        node.as_ptr(),
        Box::new(std::future::ready(format!("iteration {i}"))),
      );
      nodes.push(node);
    }
    assert_eq!(arena.remaining(), 0);
    for node in nodes {
      arena.recycle(node);
    }
    assert_eq!(arena.remaining(), 16);
  }
}

fn future_cancels_itself_before_completion() {
  let runtime = tokio::runtime::Builder::new_current_thread()
    .build()
    .unwrap();
  runtime.block_on(async {
    // A future cancels itself before it reaches completion. This future should
    // indeed get canceled and should not be polled again.
    let cancel_handle = CancelHandle::new_rc();
    let result = async {
      cancel_handle.cancel();
      yield_now().await;
      unreachable!();
    }
    .or_cancel(&cancel_handle)
    .await;
    assert_eq!(result.unwrap_err(), Canceled);
  })
}

fn future_cancels_itself_and_hangs() {
  let runtime = tokio::runtime::Builder::new_current_thread()
    .build()
    .unwrap();
  runtime.block_on(async {
    // A future cancels itself, after which it returns `Poll::Pending` without
    // setting up a waker that would allow it to make progress towards
    // completion. Nevertheless, the `Cancelable` wrapper future must finish.
    let cancel_handle = CancelHandle::new_rc();
    let result = async {
      yield_now().await;
      cancel_handle.cancel();
      pending!();
      unreachable!();
    }
    .or_cancel(&cancel_handle)
    .await;
    assert_eq!(result.unwrap_err(), Canceled);
  });
}

fn future_cancels_itself_and_completes() {
  let runtime = tokio::runtime::Builder::new_current_thread()
    .build()
    .unwrap();
  runtime.block_on(async {
    // A TryFuture attempts to cancel itself while it is getting polled, and
    // yields a result from the very same `poll()` call. Because this future
    // actually reaches completion, the attempted cancellation has no effect.
    let cancel_handle = CancelHandle::new_rc();
    let result = async {
      yield_now().await;
      cancel_handle.cancel();
      Ok::<_, io::Error>("done")
    }
    .try_or_cancel(&cancel_handle)
    .await;
    assert_eq!(result.unwrap(), "done");
  });
}

pub fn op_pledge_test_permissions(
  state: &mut OpState,
  #[serde] args: ChildPermissionsArg,
) -> Result<Uuid, deno_runtime::deno_permissions::ChildPermissionError> {
  let token = Uuid::new_v4();
  let parent_permissions = state.borrow_mut::<PermissionsContainer>();
  let worker_permissions = parent_permissions.create_child_permissions(args)?;
  let parent_permissions = parent_permissions.clone();

  if state.try_take::<PermissionsHolder>().is_some() {
    panic!("pledge test permissions called before restoring previous pledge");
  }

  state.put::<PermissionsHolder>(PermissionsHolder(token, parent_permissions));

  // NOTE: This call overrides current permission set for the worker
  state.put::<PermissionsContainer>(worker_permissions);

  Ok(token)
}
